import{c as e,Q as a,j as i,m as o}from"./chunks/framework.cL5ZtNug.js";const b=JSON.parse('{"title":"QDriverStation","description":"","frontmatter":{},"headers":[],"relativePath":"tooling/qdriverstation.md","filePath":"tooling/qdriverstation.md"}'),r={name:"tooling/qdriverstation.md"};function n(l,t,s,d,h,c){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="qdriverstation" tabindex="-1">QDriverStation <a class="header-anchor" href="#qdriverstation" aria-label="Permalink to &quot;QDriverStation&quot;">​</a></h1><p>Driver station alternative for macOS and Linux.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>The official FRC Driver Station only runs on <strong>Windows</strong>. Mac and Linux users need an alternative.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qdriverstation</span></span></code></pre></div><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>Follow the <a href="https://github.com/FRC-Utilities/QDriverStation" target="_blank" rel="noreferrer">installation guide</a>.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><ol><li>Connect to the robot network (roboRIO USB or WiFi)</li><li>Open QDriverStation</li><li>Set team number to <strong>488</strong></li><li>Click <strong>Start</strong> - it will auto-connect to the robot</li></ol><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Supported</th></tr></thead><tbody><tr><td>Enable/Disable robot</td><td>Yes</td></tr><tr><td>Set alliance color</td><td>Yes</td></tr><tr><td>Display match info</td><td>Yes</td></tr><tr><td>Joystick support</td><td>Yes</td></tr><tr><td>FRC Game Tools</td><td>No</td></tr><tr><td>DS Log Viewer</td><td>Limited</td></tr></tbody></table><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li>No FRC Game Tools integration</li><li>May have compatibility issues with newer FRC versions</li><li>No built-in log viewer (use AdvantageScope instead)</li><li>Windows DS is recommended when available</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Fix</th></tr></thead><tbody><tr><td>Can&#39;t connect to robot</td><td>Verify network connection, check team number</td></tr><tr><td>Joystick not detected</td><td>Check USB connection, restart QDriverStation</td></tr><tr><td>Robot won&#39;t enable</td><td>Check robot code is deployed and running</td></tr></tbody></table><h2 id="alternative-use-windows" tabindex="-1">Alternative: Use Windows <a class="header-anchor" href="#alternative-use-windows" aria-label="Permalink to &quot;Alternative: Use Windows&quot;">​</a></h2><p>If possible, use a Windows laptop with the official FRC Driver Station for the most reliable experience.</p>',19)])])}const p=e(r,[["render",n]]);export{b as __pageData,p as default};
